from itertools import combinations

class Solution:
    def maximizeExpressionOfThree(self, nums):
        n = len(nums)
        best = None
        for combo in combinations(range(n), 3):
            vals = [nums[i] for i in combo]
            score = sum(vals) - 2 * min(vals)
            if best is None or score > best:
                best = score
        return best

